646→// JobsStatistics is the resolver for the jobsStatistics field.
647→func (r *queryResolver) JobsStatistics(ctx context.Context, filter []*model.JobFilter, metrics []string, page *model.PageRequest, sortBy *model.SortByAggregate, groupBy *model.Aggregate, numDurationBins *string, numMetricBins *int) ([]*model.JobsStatistics, error) {
648→	startOverall := time.Now()
649→	var err error
650→	var stats []*model.JobsStatistics
651→
652→	// Top Level Defaults
653→	defaultDurationBins := "1h"
654→	defaultMetricBins := 10
655→
656→	// Build requested fields map for selective column computation
657→	statsFields := []string{"totalJobs", "totalUsers", "totalWalltime", "totalNodes", "totalCores",
658→		"totalAccs", "totalNodeHours", "totalCoreHours", "totalAccHours", "runningJobs", "shortJobs"}
659→	reqFields := make(map[string]bool, len(statsFields))
660→	fetchedMainStats := false
661→	for _, f := range statsFields {
662→		if requireField(ctx, f) {
663→			reqFields[f] = true
664→			if f != "runningJobs" && f != "shortJobs" {
665→				fetchedMainStats = true
666→			}
667→		}
668→	}
669→
670→	if fetchedMainStats {
671→		if groupBy == nil {
672→			stats, err = r.Repo.JobsStats(ctx, filter, reqFields)
673→		} else {
674→			startGrouped := time.Now()
675→			stats, err = r.Repo.JobsStatsGrouped(ctx, filter, page, sortBy, groupBy, reqFields)
676→			cclog.Infof("Timer JobsStatsGrouped call: %s", time.Since(startGrouped))
677→		}
678→	} else {
679→		stats = make([]*model.JobsStatistics, 0, 1)
680→		stats = append(stats, &model.JobsStatistics{})
681→	}
682→
683→	// runningJobs and shortJobs are already inlined in JobsStats/JobsStatsGrouped.
684→	// Only run separate count queries if main stats were not fetched.
685→	if !fetchedMainStats {
686→		if groupBy != nil {
687→			if requireField(ctx, "shortJobs") {
688→				stats, err = r.Repo.AddJobCountGrouped(ctx, filter, groupBy, stats, "short")
689→			}
690→			if requireField(ctx, "runningJobs") {
691→				stats, err = r.Repo.AddJobCountGrouped(ctx, filter, groupBy, stats, "running")
692→			}
693→		} else {
694→			if requireField(ctx, "shortJobs") {
695→				stats, err = r.Repo.AddJobCount(ctx, filter, stats, "short")
696→			}
697→			if requireField(ctx, "runningJobs") {
698→				stats, err = r.Repo.AddJobCount(ctx, filter, stats, "running")
699→			}
700→		}
701→	}
702→
703→	if err != nil {
704→		return nil, err
705→	}
706→
707→	if requireField(ctx, "histDuration") || requireField(ctx, "histNumNodes") || requireField(ctx, "histNumCores") || requireField(ctx, "histNumAccs") {
708→
709→		if numDurationBins == nil {
710→			numDurationBins = &defaultDurationBins
711→		}
712→
713→		if groupBy == nil {
714→			stats[0], err = r.Repo.AddHistograms(ctx, filter, stats[0], numDurationBins)
715→			if err != nil {
716→				return nil, err
717→			}
718→		} else {
719→			return nil, errors.New("histograms only implemented without groupBy argument")
720→		}
721→	}
722→
723→	if requireField(ctx, "histMetrics") {
724→
725→		if numMetricBins == nil {
726→			numMetricBins = &defaultMetricBins
727→		}
728→
729→		if groupBy == nil {
730→			stats[0], err = r.Repo.AddMetricHistograms(ctx, filter, metrics, stats[0], numMetricBins)
731→			if err != nil {
732→				return nil, err
733→			}
734→		} else {
735→			return nil, errors.New("metric histograms only implemented without groupBy argument")
736→		}
737→	}
738→
739→	cclog.Infof("Timer JobsStatistics overall: %s", time.Since(startOverall))
740→	return stats, nil
741→}
