744→func (r *queryResolver) JobsMetricStats(ctx context.Context, filter []*model.JobFilter, metrics []string) ([]*model.JobStats, error) {
745→	// No Paging, Fixed Order by StartTime ASC
746→	order := &model.OrderByInput{
747→		Field: "startTime",
748→		Type:  "col",
749→		Order: "ASC",
750→	}
751→
752→	jobs, err := r.Repo.QueryJobs(ctx, filter, nil, order)
753→	if err != nil {
754→		cclog.Warn("Error while querying jobs for comparison")
755→		return nil, err
756→	}
757→
758→	res := []*model.JobStats{}
759→	for _, job := range jobs {
760→		data, err := metricdispatch.LoadJobStats(job, metrics, ctx)
761→		if err != nil {
762→			cclog.Warnf("Error while loading comparison jobStats data for job id %d", job.JobID)
763→			continue
764→			// return nil, err
765→		}
766→
767→		sres := []*model.NamedStats{}
768→		for name, md := range data {
769→			sres = append(sres, &model.NamedStats{
770→				Name: name,
771→				Data: &md,
772→			})
773→		}
774→
775→		numThreadsInt := int(job.NumHWThreads)
776→		numAccsInt := int(job.NumAcc)
777→		res = append(res, &model.JobStats{
778→			ID:              int(*job.ID),
779→			JobID:           strconv.Itoa(int(job.JobID)),
780→			StartTime:       int(job.StartTime),
781→			Duration:        int(job.Duration),
782→			Cluster:         job.Cluster,
783→			SubCluster:      job.SubCluster,
784→			NumNodes:        int(job.NumNodes),
785→			NumHWThreads:    &numThreadsInt,
786→			NumAccelerators: &numAccsInt,
787→			Stats:           sres,
788→		})
789→	}
790→	return res, err
791→}
