279→// buildIntCondition creates clauses for integer range filters, using BETWEEN only if required.
280→func buildIntCondition(field string, cond *config.IntRange, query sq.SelectBuilder) sq.SelectBuilder {
281→	if cond.From != 1 && cond.To != 0 {
282→		return query.Where(field+" BETWEEN ? AND ?", cond.From, cond.To)
283→	} else if cond.From != 1 && cond.To == 0 {
284→		return query.Where(field+" >= ?", cond.From)
285→	} else if cond.From == 1 && cond.To != 0 {
286→		return query.Where(field+" <= ?", cond.To)
287→	} else {
288→		return query
289→	}
290→}
